class Solution {
    public int minMovesToMakePalindrome(String s) {
        int n = s.length();
        char[] chars = s.toCharArray();
        int moves = 0;
        for (int i = 0; i < n / 2; i++) {
            int left = i;
            int right = n - 1 - i;
            if (chars[left] == chars[right]) {
                continue;
            }
            int j = right;
            while (j > left && chars[j] != chars[left]) {
                j--;
            }
            while (j > left) {
                char temp = chars[j];
                chars[j] = chars[j - 1];
                chars[j - 1] = temp;
                j--;
                moves++;
            }
        }
        return moves;
    }
}
